# Detect OS and run appropriate Wi-Fi scan command
import subprocess
import sys

def scan_wifi():
    if sys.platform == 'win32':
        # Windows: netsh wlan show networks
        result = subprocess.run(
            ['netsh', 'wlan', 'show', 'networks'],
            capture_output=True, text=True
        )
        lines = result.stdout.split('\n')
        networks = []
        for line in lines:
            if 'SSID' in line and ':' in line and 'BSSID' not in line:
                parts = line.split(':', 1)
                if len(parts) == 2:
                    networks.append(parts[1].strip())
    elif sys.platform == 'darwin':
        # macOS: airport -s
        path = '/System/Library/PrivateFrameworks/Apple80211.framework/Versions/Current/Resources/airport'
        result = subprocess.run(
            [path, '-s'],
            capture_output=True, text=True
        )
        out = result.stdout.strip().split('\n')
        networks = [line.split()[0] for line in out[1:] if line.strip()]
    else:
        # Linux: nmcli
        result = subprocess.run(
            ['nmcli', '-t', '-f', 'SSID', 'device', 'wifi', 'list'],
            capture_output=True, text=True
        )
        networks = result.stdout.strip().split('\n')

    for network in networks:
        if network:
            print(f'Found network: {network}')

scan_wifi()

# Detect OS and run appropriate channel scan command
import subprocess
import sys

if sys.platform == 'win32':
    result = subprocess.run(
        ['netsh', 'wlan', 'show', 'networks', 'mode=bssid'],
        capture_output=True, text=True
    )
    output = result.stdout
elif sys.platform == 'darwin':
    path = '/System/Library/PrivateFrameworks/Apple80211.framework/Versions/Current/Resources/airport'
    result = subprocess.run([path, '-s'], capture_output=True, text=True)
    output = result.stdout
else:
    result = subprocess.run(
        ['iwlist', 'wlan0', 'scan'],
        capture_output=True, text=True
    )
    output = result.stdout

channels = []
for line in output.split('\n'):
    if 'Channel:' in line:
        channels.append(line.strip())

print('Detected Wi-Fi Channels:')
for ch in channels:
    print(ch)
